function minTimeToRot(grid) {
    const rows = grid.length;
    const cols = grid[0].length;
    const directions = [[1, 0], [-1, 0], [0, 1], [0, -1]];
    const queue = [];
    let freshOrangeCount = 0;

    // Initialize the queue with all rotten oranges and count fresh oranges
    for (let i = 0; i < rows; i++) {
        for (let j = 0; j < cols; j++) {
            if (grid[i][j] === 2) {
                queue.push([i, j]);
            }
            if (grid[i][j] === 1) {
                freshOrangeCount++;
            }
        }
    }

    if (freshOrangeCount === 0) return 0; // No fresh oranges to rot
    if (queue.length === 0) return -1;     // No rotten oranges to start with

    let minutes = -1;

    // Perform BFS from all initially rotten oranges
    while (queue.length > 0) {
        const size = queue.length;
        for (let k = 0; k < size; k++) {
            const [x, y] = queue.shift();
            for (const [dx, dy] of directions) {
                const i = x + dx;
                const j = y + dy;
                if (i >= 0 && i < rows && j >= 0 && j < cols && grid[i][j] === 1) {
                    grid[i][j] = 2; // Rot the orange
                    freshOrangeCount--;
                    queue.push([i, j]); // Add new rotten orange to the queue
                }
            }
        }
        minutes++;
    }

    return freshOrangeCount === 0 ? minutes : -1; // If all fresh oranges are rotted, return time; else -1
}

